import java.io.*;
import java.util.*;

public class SecureCommandExecutionExample {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter the name of the file to delete: ");
